    L = len(s)
    allowed = sorted(allowed)

    def solve(length):
        # find smallest number of given length using allowed digits, >= n if length == L
        if length > L:
            # just use smallest digit (non-zero) repeated
            if allowed[0] == 0:
                if len(allowed) == 1:
                    return None  # can't form number without leading zero
                return str(allowed[1]) + str(allowed[0]) * (length - 1)
            else:
                return str(allowed[0]) * length
        # length == L, find smallest >= s using allowed digits
        digits = [int(c) for c in s]
        result = []

        def backtrack(pos, tight):
            if pos == length:
                return []
            lo = digits[pos] if tight else 0
            for d in allowed:
                if d == 0 and pos == 0:
                    continue
                if d < lo:
                    continue
                if d > lo:
                    # fill rest with smallest allowed
                    rest = []
                    for _ in range(length - pos - 1):
                        rest.append(allowed[0])
                    return [d] + rest
                else:  # d == lo, tight
                    sub = backtrack(pos + 1, True)
                    if sub is not None:
                        return [d] + sub
            return None

        res = backtrack(0, True)
        if res is None:
            return None
        return ''.join(map(str, res))

    best = None
    for length in range(L, L + 2):
        r = solve(length)
        if r is not None:
            val = int(r)
            if val >= n:
                if best is None or val < best:
                    best = val
                break
    return best

